@app.route('/authorize')
def authorize():
    """
    Authorization endpoint.
    Handles requests from the client to authorize a user.
    """
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope', '')
    state = request.args.get('state')

    # 1. Validate required parameters
    if not all([client_id, redirect_uri, response_type]):
        # Cannot redirect to client if redirect_uri is missing or invalid
        return jsonify(create_error_response(
            "invalid_request",
            "Missing required parameters: client_id, redirect_uri, or response_type"
        )), 400

    # 2. Validate client_id
    client_info = get_client_info(client_id)
    if not client_info:
        return jsonify(create_error_response(
            "unauthorized_client",
            "Client ID is invalid.",
            state=state
        )), 400

    # 3. Validate redirect_uri using substring matching
    if not validate_redirect_uri(client_id, redirect_uri):
        # If redirect_uri is invalid, we cannot redirect back to the client.
        # Log this error and return a generic error page or JSON.
        print(f"Invalid redirect_uri for client {client_id}: {redirect_uri}")
        return jsonify(create_error_response(
            "invalid_request",
            "The provided redirect_uri does not match any registered URI for this client.",
            state=state
        )), 400

    # 4. Validate response_type
    if response_type != 'code':
        # For simplicity, only 'code' flow is supported
        error_params = create_error_response(
            "unsupported_response_type",
            "Only 'code' response_type is supported.",
            state=state
        )
        return redirect(f"{redirect_uri}?{urlencode(error_params)}")

    # 5. Store authorization request in session (for user consent page)
    session['oauth_request'] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'state': state
    }

    # 6. Render user consent page
    return render_template('consent.html',
                           client_id=client_id,
                           scope=scope,
                           redirect_uri=redirect_uri)

@app.route('/consent', methods=['POST'])
def consent():
    """
    Handles user's consent decision.
    """
    if 'oauth_request' not in session:
        return jsonify(create_error_response(
            "invalid_request",
            "No pending authorization request found."
        )), 400

    oauth_request = session.pop('oauth_request')
    client_id = oauth_request['client_id']
    redirect_uri = oauth_request['redirect_uri']
    scope = oauth_request['scope']
    state = oauth_request['state']

    if request.form.get('authorize') == 'yes':
        # User granted authorization
        auth_code = generate_token(16)
        expires_in = 300 # 5 minutes

        authorization_codes[auth_code] = {
            'client_id': client_id,
            'redirect_uri': redirect_uri,
            'scope': scope,
            'expires_at': time.time() + expires_in
        }

        # Redirect back to client with authorization code
        params = {'code': auth_code}
        if state:
            params['state'] = state

        # Parse the redirect_uri to ensure we append parameters correctly
        parsed_uri = urlparse(redirect_uri)
        query_params = parse_qs(parsed_uri.query)
        query_params.update(params)
        new_query = urlencode(query_params, doseq=True)
        final_redirect_uri = urlunparse(parsed_uri._replace(query=new_query))

        return redirect(final_redirect_uri)
    else:
        # User denied authorization
        error_params = create_error_response(
            "access_denied",
            "The resource owner denied the request.",
            state=state
        )
        return redirect(f"{redirect_uri}?{urlencode(error_params)}")

@app.route('/token', methods=['POST'])
def token():
    """
    Token endpoint.
    Exchanges authorization code for an access token.
    """
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri') # Required for 'authorization_code' grant type

    # 1. Validate grant_type
    if grant_type != 'authorization_code':
        return jsonify(create_error_response(
            "unsupported_grant_type",
            "Only 'authorization_code' grant_type is supported."
        )), 400

    # 2. Validate client credentials
    client_info = get_client_info(client_id)
    if not client_info or client_info['client_secret'] != client_secret:
        return jsonify(create_error_response(
            "invalid_client",
            "Invalid client_id or client_secret."
        )), 401 # Unauthorized

    # 3. Validate authorization code
    auth_code_info = authorization_codes.get(code)
    if not auth_code_info or auth_code_info['expires_at'] < time.time():
        return jsonify(create_error_response(
            "invalid_grant",
            "Authorization code is invalid or expired."
        )), 400

    # 4. Validate client_id and redirect_uri associated with the code
    if auth_code_info['client_id'] != client_id:
        return jsonify(create_error_response(
            "invalid_grant",
            "Authorization code was issued to a different client."
        )), 400

    # The redirect_uri in the token request MUST be identical to the redirect_uri
    # parameter in the authorization request.
    # We use exact match here, not substring, as per RFC 6749 Section 4.1.3.
    if auth_code_info['redirect_uri'] != redirect_uri:
        return jsonify(create_error_response(
            "invalid_grant",
            "Redirect URI mismatch."
        )), 400

    # 5. Invalidate the authorization code (one-time use)
    del authorization_codes[code]

    # 6. Issue access token
    access_token = generate_token()
    expires_in = 3600 # 1 hour
    scope = auth_code_info['scope']

    access_tokens[access_token] = {
        'client_id': client_id,
        'scope': scope,
        'expires_at': time.time() + expires_in
    }

    # 7. Return access token response
    response_data = {
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": expires_in,
        "scope": scope
        # "refresh_token": "..." # Optional
    }
    return jsonify(response_data), 200

# --- Example Protected Resource (for demonstration) ---

@app.route('/api/resource')
def protected_resource():
    """
    An example protected resource that requires an access token.
    """
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({"error": "unauthorized", "error_description": "Missing Authorization header"}), 401

    try:
        token_type, access_token = auth_header.split(' ', 1)
        if token_type.lower() != 'bearer':
            raise ValueError("Invalid token type")
    except ValueError:
        return jsonify({"error": "invalid_request", "error_description": "Invalid Authorization header format"}), 401

    token_info = access_tokens.get(access_token)

    if not token_info or token_info['expires_at'] < time.time():
        return jsonify({"error": "invalid_token", "error_description": "Access token is invalid or expired"}), 401

    # Token is valid, return protected data
    return jsonify({
        "message": "This is a protected resource!",
        "client_id": token_info['client_id'],
        "scope": token_info['scope'],
        "data": "Sensitive information here."
    }), 200

